7	function setPage(pageName) {
8	  pagePanels.forEach((panel) => {
9	    panel.classList.toggle("active", panel.dataset.pagePanel === pageName);
10	  });
11	  pageButtons.forEach((button) => {
12	    button.classList.toggle("active", button.dataset.page === pageName);
13	  });
14	  requestAnimationFrame(resizeAll);
15	}
16	
17	function getRace(id) {
18	  return sampleData?.races?.find((race) => race.id === id);
19	}
20	
21	function getWork(id) {
22	  return sampleData?.works?.find((work) => work.id === id);
23	}
24	
25	function getRider(id) {
26	  return sampleData?.riders?.find((rider) => rider.id === id);
27	}
28	
29	function getProjection(raceId) {
30	  return sampleData?.liveProjections?.find((projection) => projection.raceId === raceId);
31	}
32	
33	function statusText(status) {
34	  return {
35	    registration: "报名中",
36	    running: "进行中",
37	    judging: "评审中",
38	    completed: "已完成",
39	    archived: "已归档",
40	    upcoming: "即将开放",
41	  }[status] || status;
42	}
43	
44	function domainText(domain) {
45	  return {
46	    "self-dogfood": "Self-dogfood",
47	    travel: "大湾区旅行",
48	    finance: "金融投研",
49	    commerce: "网商网购",
50	    health: "健康管理",
51	    government: "电子政务",
52	    medical: "医疗随访",
53	    media: "自媒体运营",
54	    "e-commerce": "网商网购",
55	    "content-ops": "自媒体运营",
56	  }[domain] || domain;
57	}
58	
59	function escapeHtml(value) {
60	  return String(value ?? "")
61	    .replaceAll("&", "&amp;")
62	    .replaceAll("<", "&lt;")
63	    .replaceAll(">", "&gt;")
64	    .replaceAll('"', "&quot;");
65	}
66	
67	const resultCardCopy = {
68	  "genesis-dogfood-race": "第一场创世赛跑出了平台自己的起点，也留下了可以反复观看的冲线样本。",
