75	
76	function text(selector, value) {
77	  const node = document.querySelector(selector);
78	  if (node && value !== undefined && value !== null) node.textContent = value;
79	}
80	
81	function html(selector, value) {
82	  const node = document.querySelector(selector);
83	  if (node && value !== undefined && value !== null) node.innerHTML = value;
84	}
