101	function renderHomeRace(raceId) {
102	  const race = getRace(raceId);
103	  if (!race) return;
104	  currentHomeRaceId = race.id;
105	  const projection = getProjection(race.id);
106	  const submitLabel = race.live?.submitLeft || "提交开放";
107	  const riskSignals = projection?.headlineMetrics?.riskSignals ?? race.live?.riskSignals ?? 0;
108	  const asset = homeRaceAssets[race.id] || homeRaceAssets["bay-area-happy-trip"];
109	
110	  html(".hero-copy h1", escapeHtml(race.title));
111	  text(".hero-subtitle", `赛题：${race.challenge}`);
112	  html(
113	    ".hero-meta",
114	    `<span><b>${race.metrics.riders}</b> riders</span>
115	     <span><b>${race.metrics.activeRiders}</b> active</span>
116	     <span><b>${race.metrics.submittedWorks}</b> works</span>
117	     <span><b>${riskSignals}</b> signals</span>`,
118	  );
119	  html(
120	    ".hero-actions",
121	    `<button type="button" data-page="live">${escapeHtml(race.primaryCta)}</button>
122	     <button type="button" data-page="race">查看赛题</button>`,
123	  );
124	  html(
125	    ".benefit-row",
126	    `<article>
127	       <span class="icon-card">Work</span>
128	       <div>
129	         <h2>${escapeHtml(asset.workTitle)}</h2>
130	         <p>${escapeHtml(asset.workMeta)}</p>
131	         <button type="button" data-page="works">查看作品</button>
132	       </div>
133	     </article>
134	     <article>
135	       <span class="icon-card">Rider</span>
136	       <div>
137	         <h2>${escapeHtml(asset.riderName)}</h2>
138	         <p>${escapeHtml(asset.riderMeta)}</p>
139	         <button type="button" data-page="rider">查看档案</button>
140	       </div>
141	     </article>`,
142	  );
143	  document.querySelectorAll("[data-live-race]").forEach((button) => {
144	    button.classList.toggle("active", button.dataset.liveRace === race.id);
145	    button.setAttribute("aria-current", button.dataset.liveRace === race.id ? "true" : "false");
146	  });
147	}
148	
149	function renderHomeLiveSwitcher() {
150	  html(
151	    ".hero-live-switcher",
152	    `${sampleData.raceGroups.liveRaceIds
153	       .map((raceId, index) => {
154	         const race = getRace(raceId);
155	         return `<button class="${index === 0 ? "active" : ""}" type="button" data-live-race="${escapeHtml(race.id)}" aria-label="切换到${escapeHtml(race.title)}" aria-current="${index === 0 ? "true" : "false"}"></button>`;
156	       })
157	       .join("")}`,
158	  );
159	}
160	
161	function rotateHomeLiveRace() {
162	  const liveRaceIds = sampleData?.raceGroups?.liveRaceIds || [];
163	  if (liveRaceIds.length < 2 || !document.querySelector(".page-home.active")) return;
164	  const currentIndex = Math.max(0, liveRaceIds.indexOf(currentHomeRaceId));
165	  const nextRaceId = liveRaceIds[(currentIndex + 1) % liveRaceIds.length];
166	  renderHomeRace(nextRaceId);
167	  requestAnimationFrame(resizeAll);
168	}
169	
170	function restartHomeRaceCarousel() {
171	  window.clearInterval(homeRaceCarouselTimer);
172	  homeRaceCarouselTimer = window.setInterval(rotateHomeLiveRace, 6800);
173	}
