449	function resizeCanvas(canvas) {
450	  const rect = canvas.getBoundingClientRect();
451	  const scale = window.devicePixelRatio || 1;
452	  canvas.width = Math.max(1, Math.floor(rect.width * scale));
453	  canvas.height = Math.max(1, Math.floor(rect.height * scale));
454	  canvas.getContext("2d").setTransform(scale, 0, 0, scale, 0, 0);
455	}
456	
457	function resizeAll() {
458	  canvases.forEach(({ node }) => resizeCanvas(node));
459	}
