461	function racePoint(progress, lane, width, height, theme) {
462	  const yBase = theme === "home" ? 0.63 : 0.55;
463	  return {
464	    x: width * (0.06 + progress * 0.88),
465	    y:
466	      height *
467	      (yBase +
468	        Math.sin(progress * Math.PI * 2.8 + lane * 3.6) * 0.16 +
469	        Math.cos(progress * Math.PI * 1.35) * 0.08 +
470	        (lane - 0.5) * 0.18),
471	  };
472	}
473	
474	function drawSpeedLines(ctx, width, height, dark) {
475	  ctx.save();
476	  ctx.globalAlpha = dark ? 0.42 : 0.3;
477	  for (let i = 0; i < 34; i += 1) {
478	    const y = height * (0.12 + i * 0.026);
479	    const start = -width * 0.12 + i * 17;
480	    const end = width * (0.92 + (i % 6) * 0.02);
481	    const gradient = ctx.createLinearGradient(start, y, end, y - 60);
482	    gradient.addColorStop(0, "rgba(22,140,255,0)");
483	    gradient.addColorStop(0.45, dark ? "rgba(48,216,255,0.42)" : "rgba(22,140,255,0.26)");
484	    gradient.addColorStop(1, "rgba(22,140,255,0)");
485	    ctx.strokeStyle = gradient;
486	    ctx.lineWidth = i % 5 === 0 ? 5 : 2;
487	    ctx.beginPath();
488	    ctx.moveTo(start, y);
489	    ctx.lineTo(end, y - height * 0.22);
490	    ctx.stroke();
491	  }
492	  ctx.restore();
493	}
494	
495	function drawBackground(ctx, width, height, theme) {
496	  const dark = theme === "screen";
497	  ctx.clearRect(0, 0, width, height);
498	  const bg = ctx.createLinearGradient(0, 0, width, height);
499	  bg.addColorStop(0, dark ? "#06164a" : "#ffffff");
500	  bg.addColorStop(0.55, dark ? "#08215f" : "#eef7ff");
501	  bg.addColorStop(1, dark ? "#02091e" : "#dcecff");
502	  ctx.fillStyle = bg;
503	  ctx.fillRect(0, 0, width, height);
504	  drawSpeedLines(ctx, width, height, dark);
505	
506	  const horizon = dark ? height * 0.7 : height * 0.62;
507	  ctx.strokeStyle = dark ? "rgba(255,255,255,0.16)" : "rgba(7,91,236,0.18)";
508	  ctx.lineWidth = 2;
509	  for (let i = 0; i < 10; i += 1) {
510	    ctx.beginPath();
511	    ctx.moveTo(width * 0.04, horizon + i * 18);
512	    ctx.quadraticCurveTo(width * 0.52, horizon - 110 + i * 6, width * 0.96, horizon + i * 22);
513	    ctx.stroke();
514	  }
515	}
516	
517	function drawTrack(ctx, width, height, theme) {
518	  const dark = theme === "screen";
519	  ctx.strokeStyle = dark ? "rgba(48,216,255,0.72)" : "rgba(7,91,236,0.52)";
520	  ctx.lineWidth = theme === "screen" ? 6 : 4;
521	  ctx.beginPath();
522	  ctx.moveTo(width * 0.08, height * 0.82);
523	  ctx.bezierCurveTo(width * 0.24, height * 0.22, width * 0.48, height * 0.86, width * 0.68, height * 0.42);
524	  ctx.bezierCurveTo(width * 0.78, height * 0.22, width * 0.88, height * 0.44, width * 0.95, height * 0.26);
525	  ctx.stroke();
526	}
527	
528	function drawRiderMarker(ctx, rider, width, height, time, theme, index) {
529	  const dark = theme === "screen";
530	  const progress = (rider.phase + time * rider.speed) % 1;
531	  const point = racePoint(progress, rider.lane, width, height, theme);
532	  const tail = racePoint(Math.max(0, progress - 0.09), rider.lane, width, height, theme);
533	  const radius = theme === "screen" ? 16 : 11;
534	  const trail = ctx.createLinearGradient(tail.x, tail.y, point.x, point.y);
535	  trail.addColorStop(0, "rgba(255,255,255,0)");
536	  trail.addColorStop(1, rider.color);
537	  ctx.strokeStyle = trail;
538	  ctx.lineWidth = theme === "screen" ? 8 : 5;
539	  ctx.beginPath();
540	  ctx.moveTo(tail.x, tail.y);
541	  ctx.lineTo(point.x, point.y);
542	  ctx.stroke();
543	  ctx.fillStyle = "rgba(255,255,255,0.95)";
544	  ctx.beginPath();
545	  ctx.arc(point.x, point.y, radius, 0, Math.PI * 2);
546	  ctx.fill();
547	  ctx.strokeStyle = rider.color;
548	  ctx.lineWidth = 5;
549	  ctx.stroke();
550	  ctx.fillStyle = dark ? "#ffffff" : "#06164a";
551	  ctx.font = `950 ${theme === "screen" ? 24 : 15}px Arial, sans-serif`;
552	  ctx.fillText(rider.name, point.x + radius + 8, point.y - radius - index);
553	}
554	
555	function drawOverlay(ctx, width, height, time, theme) {
556	  const dark = theme === "screen";
557	  const signal = Math.round((getRace(sampleData.raceGroups.featuredRaceId)?.live?.ridingSignal || 75) + Math.sin(time / 560) * 4);
558	  const cardX = theme === "home" ? 28 : 24;
559	  const cardY = theme === "home" ? 36 : 24;
560	  const labelY = cardY + (theme === "screen" ? 34 : 26);
561	  const valueY = cardY + (theme === "screen" ? 80 : 59);
562	  ctx.fillStyle = dark ? "rgba(255,255,255,0.12)" : "rgba(255,255,255,0.82)";
563	  ctx.strokeStyle = dark ? "rgba(255,255,255,0.24)" : "rgba(7,91,236,0.22)";
564	  ctx.lineWidth = 2;
565	  ctx.beginPath();
566	  ctx.roundRect(cardX, cardY, theme === "screen" ? 270 : 180, theme === "screen" ? 112 : 78, 4);
567	  ctx.fill();
568	  ctx.stroke();
569	  ctx.fillStyle = dark ? "#bfe3ff" : "#075bec";
570	  ctx.font = `950 ${theme === "screen" ? 15 : 12}px Arial, sans-serif`;
571	  ctx.fillText("RIDING SIGNAL", cardX + 18, labelY);
572	  ctx.fillStyle = dark ? "#ffffff" : "#075bec";
573	  ctx.font = `950 italic ${theme === "screen" ? 48 : 30}px Arial, sans-serif`;
574	  ctx.fillText(`${signal}%`, cardX + 18, valueY);
575	  text("#signalValue", `${signal}%`);
576	}
577	
578	function drawFrame(time) {
579	  canvases.forEach(({ node, theme }) => {
580	    const rect = node.getBoundingClientRect();
581	    if (rect.width < 1 || rect.height < 1) return;
582	    const ctx = node.getContext("2d");
583	    drawBackground(ctx, rect.width, rect.height, theme);
584	    drawTrack(ctx, rect.width, rect.height, theme);
585	    riders.forEach((rider, index) => drawRiderMarker(ctx, rider, rect.width, rect.height, time, theme, index));
586	    drawOverlay(ctx, rect.width, rect.height, time, theme);
587	  });
588	  requestAnimationFrame(drawFrame);
589	}
