591	if (!CanvasRenderingContext2D.prototype.roundRect) {
592	  CanvasRenderingContext2D.prototype.roundRect = function roundRect(x, y, width, height, radius) {
593	    this.moveTo(x + radius, y);
594	    this.lineTo(x + width - radius, y);
595	    this.quadraticCurveTo(x + width, y, x + width, y + radius);
596	    this.lineTo(x + width, y + height - radius);
597	    this.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
598	    this.lineTo(x + radius, y + height);
599	    this.quadraticCurveTo(x, y + height, x, y + height - radius);
600	    this.lineTo(x, y + radius);
601	    this.quadraticCurveTo(x, y, x + radius, y);
602	    return this;
603	  };
604	}
